B.RP=new A.dK("wbc","White Blood Cells","WBC","\xd710\xb3/\xb5L","CBC",4.5,11,3,null,2,null,!1,"Infection-fighting cells. Low WBC (neutropenia) means high infection risk during chemo nadir.")
B.RK=new A.dK("anc","Abs. Neutrophil Count","ANC","\xd710\xb3/\xb5L","CBC",1.5,8,1,null,0.5,null,!1,"Most critical infection-risk marker. ANC <0.5 = severe neutropenia. Report fever \u226538\xb0C immediately.")
B.RN=new A.dK("rbc","Red Blood Cells","RBC","\xd710\u2076/\xb5L","CBC",3.8,5.2,3.2,null,2.5,null,!1,"Oxygen carriers. Low RBC = anemia \u2192 fatigue, breathlessness.")
B.RW=new A.dK("hemoglobin","Hemoglobin","Hgb","g/dL","CBC",12,17.5,10,null,8,null,!1,"Hemoglobin carries oxygen. Levels <10 g/dL may require intervention. Monitor fatigue closely.")
B.RV=new A.dK("platelets","Platelets","PLT","\xd710\xb3/\xb5L","CBC",150,400,75,null,50,null,!1,"Clotting cells. Low platelets = bleeding risk. Avoid NSAIDs. Report unusual bruising.")
B.RQ=new A.dK("hematocrit","Hematocrit","Hct","%","CBC",36,52,30,null,24,null,!1,"Percentage of blood volume that is red cells. Closely follows hemoglobin trends.")
B.RU=new A.dK("creatinine","Creatinine","Creat","mg/dL","Metabolic",0.6,1.2,null,1.5,null,2,!1,"Kidney function. Elevated creatinine may require dose adjustments of chemo drugs.")
B.RX=new A.dK("alt","Liver ALT","ALT","U/L","Metabolic",7,56,null,120,null,200,!1,"Liver enzyme. Elevated after some chemo drugs. Limit alcohol. Monitor trajectory.")
B.RJ=new A.dK("ast","Liver AST","AST","U/L","Metabolic",10,40,null,80,null,120,!1,"Another liver enzyme. Rising AST alongside ALT needs urgent review.")
B.RS=new A.dK("bilirubin","Total Bilirubin","Bili","mg/dL","Metabolic",0.2,1.2,null,2,null,3,!1,"Bile pigment. High bilirubin causes jaundice. May indicate liver or bile duct issues.")
B.RR=new A.dK("glucose","Blood Glucose","Gluc","mg/dL","Metabolic",70,100,null,140,60,250,!1,"May be elevated by corticosteroids in chemo regimens. Monitor for diabetic symptoms.")
B.RI=new A.dK("sodium","Sodium","Na","mEq/L","Metabolic",136,145,130,null,125,null,!1,"Electrolyte balance. Low sodium often from vomiting/poor intake. Stay well hydrated.")
B.RL=new A.dK("potassium","Potassium","K","mEq/L","Metabolic",3.5,5,3,5.5,2.5,6,!1,"Critical electrolyte. Low potassium causes muscle weakness and heart rhythm issues.")
B.RO=new A.dK("ca153","Cancer Antigen 15-3","CA 15-3","U/mL","Tumor Markers",0,31,null,50,null,80,!0,"Breast cancer marker. Declining = strong treatment response. Never interpret alone without imaging.")
B.RT=new A.dK("cea","Carcinoembryonic Ag","CEA","ng/mL","Tumor Markers",0,3,null,6,null,10,!0,"Colorectal/breast marker. Steady decline = positive response. Single readings less useful than trend.")
B.RM=new A.dK("ca125","Cancer Antigen 125","CA-125","U/mL","Tumor Markers",0,35,null,65,null,100,!0,"Ovarian cancer marker. Track trend over treatment cycles, not individual values.")
B.RH=new A.dK("psa","PSA","PSA","ng/mL","Tumor Markers",0,4,null,10,null,20,!0,"Prostate cancer marker. Rapid doubling is more significant than absolute value.")
